    "cases.capture_daywork_and_time_and_materials.step.submit.out.valuation": "Betalingsvurdering",
    "cases.capture_daywork_and_time_and_materials.step.submit.title": "Send det inn mot kontrakten",
    "cases.capture_daywork_and_time_and_materials.step.submit.what": "Prissett de avtalte ressursene med kontraktens regningsarbeidspriser eller prosentsatser, legg ved de signerte sedlene og instruksjonen, og send inn vurderingen slik at den flyter inn i neste betaling.",
    "cases.capture_daywork_and_time_and_materials.step.submit.why": "Regningsarbeid som aldri blir prissatt og sendt inn er arbeid du gjorde gratis. Å gjøre den signerte protokollen om til en vurdering mot kontrakten er steget som faktisk gjør innsatsen om til penger.",
    "cases.capture_daywork_and_time_and_materials.title": "Registrer regningsarbeid og medgått tid og materialer",
    "cases.carbon_from_bim_6d.desc": "Gjør en konvertert BIM-modell om til et klimagassavtrykk. Auto-berikelse leser mengder fra geometrien og parer hvert materiale med en utslippsfaktor, deretter setter du et reduksjonsmål og utsteder rapporten. Fem steg.",
    "cases.carbon_from_bim_6d.step.enrich.in.factors": "Bibliotek med utslippsfaktorer",
    "cases.carbon_from_bim_6d.step.enrich.in.inventory": "Åpen oversikt",
    "cases.carbon_from_bim_6d.step.enrich.in.materials": "Elementmaterialer",
    "cases.carbon_from_bim_6d.step.enrich.out.entries": "Bekreftede klimagassoppføringer",
    "cases.carbon_from_bim_6d.step.enrich.out.preview": "Forhåndsvisning av matchede linjer",
    "cases.carbon_from_bim_6d.step.enrich.title": "Auto-beriker innebygd klimagass fra BIM",
    "cases.carbon_from_bim_6d.step.enrich.what": "Kjør Auto-berikelse fra BIM inne i oversikten. Velg modellen, se gjennom de foreslåtte linjene i forhåndsvisningen, og bekreft. Hvert elementmateriale matches til en utslippsfaktor og mengden hentes rett fra geometrien. Ingenting lagres før du godtar det.",
    "cases.carbon_from_bim_6d.step.enrich.why": "Dette er hvor 6D beviser sin verdi. I stedet for å taste inn betong, stål og isolasjon linje for linje, får du en fullstendig innebygd liste fra modellen på sekunder, og hver rad viser hvor sikker matchen er.",
    "cases.carbon_from_bim_6d.step.import-model.in.file": "Konvertert modellfil",
    "cases.carbon_from_bim_6d.step.import-model.in.project": "Prosjektjournal",
    "cases.carbon_from_bim_6d.step.import-model.out.elements": "Elementer med materialer",
    "cases.carbon_from_bim_6d.step.import-model.out.quantities": "Mengder fra geometri",
    "cases.carbon_from_bim_6d.step.import-model.title": "Importer en BIM-modell",
    "cases.carbon_from_bim_6d.step.import-model.what": "Åpne BIM og importer den konverterte modellen for denne jobben. Når konverteringen er ferdig, har hver vegg, dekke og søyle både materialmerket og mengden målt fra den solide geometrien.",
    "cases.carbon_from_bim_6d.step.import-model.why": "Hele avtrykket leses fra modellen, så søppel inn betyr søppel ut. En konvertert modell gir klimagassmatchen et rent materiale og en reell mengde i stedet for et tall noen skrev inn for hånd.",
    "cases.carbon_from_bim_6d.step.inventory.in.model": "Importert BIM-modell",
    "cases.carbon_from_bim_6d.step.inventory.in.project": "Prosjektjournal",
    "cases.carbon_from_bim_6d.step.inventory.out.boundary": "Systemgrense satt",
    "cases.carbon_from_bim_6d.step.inventory.out.inventory": "Tom klimagassoversikt",
    "cases.carbon_from_bim_6d.step.inventory.title": "Åpne Klimagass og start en oversikt",
    "cases.carbon_from_bim_6d.step.inventory.what": "Gå til Klimagass og åpne en ny oversikt for prosjektet. Fest systemgrensen på forhånd, vugge til port for skallet eller vugge til grav når du også trenger bruksfasen og livsløpsslutten.",
    "cases.carbon_from_bim_6d.step.inventory.why": "Valg av grense styrer hele resultatet, så fest den før noen oppføring lander. To avtrykk kan bare sammenlignes når de dekker de samme fasene, og oversikten er det ene stedet hver materiallinje summeres.",
    "cases.carbon_from_bim_6d.step.review.in.confidence": "Flagg for matchsikkerhet",
    "cases.carbon_from_bim_6d.step.review.in.entries": "Berikede klimagassoppføringer",
    "cases.carbon_from_bim_6d.step.review.out.footprint": "Godkjent avtrykk",
    "cases.carbon_from_bim_6d.step.review.out.verified": "Verifiserte klimagasslinjer",
    "cases.carbon_from_bim_6d.step.review.title": "Gjennomgå de koblede oppføringene og sikkerheten",
    "cases.carbon_from_bim_6d.step.review.what": "Gå gjennom de tillagte linjene. Hver oppføring peker tilbake til BIM-elementet som produserte den og viser en matchsikkerhet, så åpne de gule og røde radene først og korriger faktoren eller mengden der paringen ser feil ut.",
    "cases.carbon_from_bim_6d.step.review.why": "Verktøyet foreslår, kalkulatøren godkjenner. En generisk faktor på et spesialprodukt kan svinge totalen med tonn, så sikkerhetsflagget forteller deg nøyaktig hvilke rader som fortjener et nytt blikk.",
    "cases.carbon_from_bim_6d.step.target.in.area": "Gulvareal",
    "cases.carbon_from_bim_6d.step.target.in.footprint": "Verifisert avtrykk",
    "cases.carbon_from_bim_6d.step.target.out.report": "Klimagassrapport",
    "cases.carbon_from_bim_6d.step.target.out.target": "Reduksjonsmål",
    "cases.carbon_from_bim_6d.step.target.title": "Sett et mål og rapporter",
    "cases.carbon_from_bim_6d.step.target.what": "Sett et reduksjonsmål, enten som en absolutt sum eller per kvadratmeter gulvareal, og generer så rapporten for perioden i rammeverket kunden ber om. Målet oppdateres live etter hvert som oversikten endres.",
    "cases.carbon_from_bim_6d.step.target.why": "Et rått klimagasstall overbeviser ingen alene. Et mål trekker opp linjen du prøver å slå, og den eksporterte rapporten gjør avtrykket til en datert dokumentasjon du kan legge fram for en vurderer eller en planmyndighet.",
    "cases.carbon_from_bim_6d.title": "Hent ut 6D klimagassavtrykk fra en BIM-modell",
    "cases.change_register_and_impact.desc": "Registrer hver endring i ett register, les tids- og kostnadskonsekvensen skåret mot den reelle prosjektregnskapsboken, og legg trenden fram for kunden før den blir en overraskelse.",
    "cases.change_register_and_impact.step.impact.in.ledger": "Prosjektkostnadsregnskap",
    "cases.change_register_and_impact.step.impact.in.register": "Endringsregister",
    "cases.change_register_and_impact.step.impact.out.impact": "Tids- og kostnadskonsekvens",
    "cases.change_register_and_impact.step.impact.out.pareto": "Pareto for de største endringene",
    "cases.change_register_and_impact.step.impact.title": "Les konsekvensen",
    "cases.change_register_and_impact.step.impact.what": "Les tids- og kostnadskonsekvensen skåret mot det faktiske prosjektregnskapet, Paretoen over de få endringene som driver mesteparten av pengene, og hastigheten nye fortsetter å komme inn med.",
    "cases.change_register_and_impact.step.impact.why": "Tjue små endringer føles ufarlige helt til de legger seg opp til den som sprenger budsjettet. Å skåre konsekvens mot reelt forbruk er det som avdekker driften mens det fortsatt er rom til å handle.",
    "cases.change_register_and_impact.step.register.in.instruction": "Byggeplassinstruksjon",
    "cases.change_register_and_impact.step.register.in.memo": "E-post eller byggeplassnotat",
    "cases.change_register_and_impact.step.register.out.entry": "Endringsregisteroppføring",
    "cases.change_register_and_impact.step.register.out.value": "Registrert status og verdi",
    "cases.change_register_and_impact.step.register.title": "Registrer endringen",
    "cases.change_register_and_impact.step.register.what": "Registrer hver endring idet den kommer inn med opprinnelse, gjeldende status og verdi i ett samlet register, slik at ingen instruksjon bare blir en linje begravet i en e-posttråd.",
    "cases.change_register_and_impact.step.register.why": "En endring som aldri kom med i registeret er en endring du ikke får betalt for. Én delt liste er det som gjør et virvar av muntlige instruksjoner og byggeplassnotater til en kravbar, reviderbar posisjon.",
    "cases.change_register_and_impact.step.report.in.forecast": "Prognostisert sluttoppgjør",
