    "cases.inspect_and_close_ncr.step.ncr.out.ncr": "Loggført avvik",
    "cases.inspect_and_close_ncr.step.ncr.out.owner": "Navngitt ansvarlig og frist",
    "cases.inspect_and_close_ncr.step.ncr.title": "Reis et avvik",
    "cases.inspect_and_close_ncr.step.ncr.what": "Ved underkjenning, reis avviket direkte fra inspeksjonen. Beskriv mangelen tydelig, legg ved bildene og den underkjente sjekklisten, og navngi parten som må rette den opp og fristen den forfaller på.",
    "cases.inspect_and_close_ncr.step.ncr.why": "Et avvik gjør en løs klage om til et sporet tiltak med en navngitt ansvarlig og en frist. En mangel nevnt i forbifarten bygges over og glemmes, mens en mangel på registeret følges opp til den er rettet.",
    "cases.inspect_and_close_ncr.title": "Inspiser arbeid og lukk et avvik",
    "cases.issue_a_controlled_drawing_revision.desc": "Registrer en ny tegningsrevisjon, merk den gamle som utgått, distribuer den til hvert fag som bygger etter den, og bekreft at det gjeldende arket er det som henger på veggen ute på arbeidsstedet.",
    "cases.issue_a_controlled_drawing_revision.step.register.in.drawing": "Ny tegningsrevisjon",
    "cases.issue_a_controlled_drawing_revision.step.register.in.register": "Dokumentregister",
    "cases.issue_a_controlled_drawing_revision.step.register.out.registered": "Registrert revisjon",
    "cases.issue_a_controlled_drawing_revision.step.register.out.superseded": "Gammelt ark utgått",
    "cases.issue_a_controlled_drawing_revision.step.register.title": "Registrer den nye revisjonen",
    "cases.issue_a_controlled_drawing_revision.step.register.what": "Legg den nye revisjonen inn i dokumentregisteret med nummer, dato og revisjonsbokstav, merk forrige versjon som utgått, og noter hva som endret seg slik at leseren vet hvorfor det ble oppdatert.",
    "cases.issue_a_controlled_drawing_revision.step.register.why": "To gjeldende kopier av samme tegning er hvordan en vegg bygges etter forrige måneds geometri. Ett kontrollert register, med den gamle revisjonen tydelig utgått, er det som ikke etterlater tvil om hvilket ark som er sannheten.",
    "cases.issue_a_controlled_drawing_revision.step.transmit.in.recipients": "Distribusjonsliste for fag",
    "cases.issue_a_controlled_drawing_revision.step.transmit.in.revision": "Registrert revisjon",
    "cases.issue_a_controlled_drawing_revision.step.transmit.out.record": "Leveringsprotokoll",
    "cases.issue_a_controlled_drawing_revision.step.transmit.out.transmittal": "Utstedt oversendelse",
    "cases.issue_a_controlled_drawing_revision.step.transmit.title": "Distribuer den til fagene",
    "cases.issue_a_controlled_drawing_revision.step.transmit.what": "Send en oversendelse til hvert fag og underentreprenør som arbeider etter den tegningen, med revisjonen som er utstedt og datoen, og hold protokoll over hvem den gikk til og når.",
    "cases.issue_a_controlled_drawing_revision.step.transmit.why": "En revisjon som ligger i registeret men aldri når laget som støper dekket har ikke endret noe. Oversendelsesprotokollen er også ditt bevis på at faget hadde gjeldende informasjon da de bygde.",
    "cases.issue_a_controlled_drawing_revision.step.verify.in.current": "Siste revisjon",
