    "cases.issue_a_permit_to_work.step.raise-permit.what": "Reis tillatelsen for oppgaven i HMS Avansert, varmt arbeid, trangt rom eller arbeid i høyden, og sett tiltakene og gyldighetsvinduet.",
    "cases.issue_a_permit_to_work.step.raise-permit.why": "Høyrisikoarbeid uten en aktiv tillatelse og klare tiltak er hvordan folk blir skadet og jobben blir stanset. Vinduet holder den gyldig bare mens tiltakene gjelder.",
    "cases.issue_a_permit_to_work.title": "Reis en arbeidstillatelse",
    "cases.issue_a_procurement_and_buying_schedule.desc": "Gjør mengdefortegnelsen og fremdriftsplanen om til en innkjøpsplan: list opp pakkene som skal kjøpes inn, sett leveringstider og bestillingsfrister bakover fra fremdriftsplanen, tilbudsinnhent eller pris hver pakke, og følg opp hver bestilling slik at ingenting kjøpes for sent.",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.in.packages": "Innkjøpspakker",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.in.programme": "Fremdriftsplandatoer",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.out.leadtimes": "Leveringstider",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.out.orderby": "Siste bestillingsdatoer",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.title": "Sett leveringstider og bestillingsfrister",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.what": "Sett produksjons- og leveringstiden for hver pakke, og regn deretter bakover fra datoen materialet trengs på byggeplassen ifølge fremdriftsplanen for å fastsette siste dato bestillingen må plasseres.",
    "cases.issue_a_procurement_and_buying_schedule.step.leadtimes.why": "De fleste sene materialer blir ikke kjøpt sent ved et uhell, de blir kjøpt i tide mot feil dato. Å regne bakover fra fremdriftsplanen er det som gjør en ønskeliste om til en plan med reelle frister.",
    "cases.issue_a_procurement_and_buying_schedule.step.order.in.dates": "Bestillingsfrister",
    "cases.issue_a_procurement_and_buying_schedule.step.order.in.price": "Avtalt pris og leverandør",
    "cases.issue_a_procurement_and_buying_schedule.step.order.out.committed": "Forpliktet kostnad",
    "cases.issue_a_procurement_and_buying_schedule.step.order.out.order": "Innkjøpsordre reist",
    "cases.issue_a_procurement_and_buying_schedule.step.order.title": "Plasser bestillinger og engasjer leverandører",
    "cases.issue_a_procurement_and_buying_schedule.step.order.what": "Tildel hver pakke til sin valgte leverandør eller underentreprenør og reis bestillingen, slik at den forpliktede kostnaden bokføres og leveransen låses mot bestillingsfristen i planen.",
    "cases.issue_a_procurement_and_buying_schedule.step.order.why": "En avtalt pris som ikke er bestilt er ikke en leveranse. Å plassere bestillingen er punktet hvor leverandøren er bundet til datoen, og punktet hvor din forpliktede kostnad blir reell og sporbar.",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.in.boq": "Priset mengdefortegnelse",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.in.trades": "Fagfordeling",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.out.packages": "Innkjøpspakker",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.out.quantities": "Pakkemengder",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.title": "Del mengdefortegnelsen inn i innkjøpspakker",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.what": "Grupper den prisede mengdefortegnelsen i pakkene du faktisk skal kjøpe inn, én per fag eller leveranseposisjon, slik at hver linje i innkjøpsplanen tilsvarer en reell bestilling fremfor en løs samling poster.",
    "cases.issue_a_procurement_and_buying_schedule.step.packages.why": "En innkjøpsplan bygget rett fra mengdefortegnelsen bærer de riktige mengdene og verdiene fra starten, slik at ingenting stille faller mellom to pakker og forblir ukjøpt.",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.in.dates": "Siste bestillingsdatoer",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.in.packages": "Innkjøpspakker",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.out.price": "Fast pris og leverandør",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.out.quotes": "Leverandørtilbud",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.title": "Tilbudsinnhent eller pris hver pakke",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.what": "Send pakkene med de tidligste bestillingsfristene ut på forespørsel først, samle inn tilbud, og fastsett en fast pris og leverandør for hver, slik at innkjøpsplanen bærer et forpliktet tall, ikke et gjett.",
    "cases.issue_a_procurement_and_buying_schedule.step.tender.why": "Å prise i rekkefølge etter hastegrad betyr at de langvarige pakkene avgjøres mens det fortsatt er tid til å forhandle, i stedet for å hastes gjennom til hvilken som helst pris uken de trengs.",
    "cases.issue_a_procurement_and_buying_schedule.step.track.in.orders": "Plasserte bestillinger",
    "cases.issue_a_procurement_and_buying_schedule.step.track.in.schedule": "Innkjøpsplan",
