    "cases.localize_an_estimate_to_a_region.step.apply.out.rates": "Lokaliserte enhetspriser",
    "cases.localize_an_estimate_to_a_region.step.apply.out.rerated": "Omprisede fortegnelse",
    "cases.localize_an_estimate_to_a_region.step.apply.title": "Bruk lokale priser og faktorer",
    "cases.localize_an_estimate_to_a_region.step.apply.what": "Reprise fortegnelsen mot det regionale grunnlaget og bruk lokasjons- og valutajusteringsfaktorene, hold mengdene som de er slik at bare prisingen flytter og omfanget står fast.",
    "cases.localize_an_estimate_to_a_region.step.apply.why": "Å holde mengdene faste og bare endre prisene holder de to effektene, omfang og pris, rent adskilt. Slik ser du nøyaktig hvor mye av det nye tallet som er regionen og hvor mye som er designet.",
    "cases.localize_an_estimate_to_a_region.step.base.in.estimate": "Priset estimat",
    "cases.localize_an_estimate_to_a_region.step.base.in.region": "Målregion og -valuta",
    "cases.localize_an_estimate_to_a_region.step.base.out.base": "Regionalt kostnadsgrunnlag",
    "cases.localize_an_estimate_to_a_region.step.base.out.coverage": "Fagdekningskontroll",
    "cases.localize_an_estimate_to_a_region.step.base.title": "Velg det regionale kostnadsgrunnlaget",
    "cases.localize_an_estimate_to_a_region.step.base.what": "Velg kostnadsgrunnlaget som matcher regionen og valutaen arbeidet skal bygges i, og sjekk at det dekker fagene i fortegnelsen din i stedet for å etterlate hull du må prise for hånd.",
    "cases.localize_an_estimate_to_a_region.step.base.why": "Lønnssatser, materialpriser og produktivitet varierer sterkt fra én region til en annen, så en pris som var riktig ett sted kan være langt utenfor på et annet. Å starte fra det lokale grunnlaget er det som holder estimatet forsvarbart i det nye markedet.",
    "cases.localize_an_estimate_to_a_region.step.validate.in.benchmarks": "Regionale referansetall",
