    "cases.prepare_a_method_statement_and_risk_assessment.desc": "Bygg en arbeidsbeskrivelse og risikovurdering for en arbeidspakke før den starter, beskriv den sikre metoden, identifiser farer og tiltak, tildel ansvar, få den gjennomgått og utstedt, og gjør den tilgjengelig på byggeplassen.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.in.approved": "Godkjent SJA-dokument",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.in.crew": "Utførende lag",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.out.briefed": "Briefet lag",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.out.filed": "SJA-dokument i prosjektfiler",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.title": "Gjør det tilgjengelig på byggeplassen",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.what": "Lagre det utstedte SJA-dokumentet i prosjektfilene der laget og enhver inspektør kan nå det, og brief laget på det før pakken starter.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.why": "Et SJA-dokument låst inne på et kontor beskytter ingen. Å ha gjeldende versjon på byggeplassen, briefet til laget, er det som gjør det til et fungerende dokument og beviser at arbeidet ble planlagt sikkert.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.in.method": "Arbeidsbeskrivelse",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.in.steps": "Arbeidstrinn",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.out.controls": "Tiltak og risikovurderinger",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.out.hazards": "Fareliste",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.title": "Identifiser farer og tiltak",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.what": "Gå gjennom hvert trinn og list opp farene det skaper, sett deretter tiltaket for hver, og vurder risikoen før og etter tiltaket slik at farenivået er tydelig.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.why": "Risikovurderingen er der du beviser at metoden er trygg, ikke bare gjennomførbar. Å vurdere risikoen før og etter tiltak viser nøyaktig hvorfor hvert tiltak er der og hva som skjer uten det.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.in.drawings": "Tegninger og plantegning",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.in.package": "Omfang for arbeidspakke",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.out.method": "Arbeidsbeskrivelse",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.out.sequence": "Arbeidssekvens",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.title": "Beskriv den sikre metoden",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.what": "Beskriv hvordan arbeidspakken faktisk skal utføres trinn for trinn, sekvensen, maskiner og utstyr, adkomst og personene involvert, i et klart språk et lag kan følge.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.why": "En arbeidsbeskrivelse omgjør en vag plan til en avtalt arbeidsmåte alle slutter seg til. Når sekvensen er skrevet ned, jobber hele laget etter det samme bildet i stedet for å improvisere.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.in.controls": "Tiltak",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.in.team": "Byggeplassteam og roller",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.out.matrix": "Ansvarsmatrise",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.out.owners": "Tildelte ansvarshavere",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.title": "Tildel ansvar",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.what": "Navngi hvem som er ansvarlig for hvert tiltak og hver kontroll, arbeidslederen, ansvarlig for løft, førstehjelperen, slik at hvert oppdrag i planen har en eier.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.why": "Et tiltak uten et navn på seg er et tiltak ingen utfører. Å tildele ansvar er det som gjør papirarbeidet til noe som faktisk skjer på byggeplassen.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.in.rams": "Utkast til SJA-dokument",
