    "cases.report_and_action_a_near_miss.step.verify.out.closed": "Nesten-ulykke lukket",
    "cases.report_and_action_a_near_miss.step.verify.out.verified": "Tiltak verifisert",
    "cases.report_and_action_a_near_miss.step.verify.title": "Verifiser tiltaket på befaringen",
    "cases.report_and_action_a_near_miss.step.verify.what": "Gå tilbake til stedet på neste inspeksjonsbefaring, bekreft at det korrigerende tiltaket virkelig er gjennomført og holder, og lukk nesten-ulykken med dokumentasjonen vedlagt.",
    "cases.report_and_action_a_near_miss.step.verify.why": "Et tiltak merket utført på kontoret er ikke det samme som en sperring som faktisk står på bakken. Å sjekke det på befaringen er det som gjør en god intensjon til beskyttelse en arbeider kan stole på.",
    "cases.report_and_action_a_near_miss.title": "Rapporter og følg opp en nesten-ulykke",
    "cases.review_and_mitigate_project_risks.desc": "Gå gjennom risikoregisteret med jevne mellomrom, vurder sannsynlighet og konsekvens ærlig, og tildel en tiltakseier før en risiko blir et reelt problem.",
    "cases.review_and_mitigate_project_risks.step.mitigate.in.risks": "Aktive risikoer",
