    "cases.set_up_a_new_project.step.schedule.out.fronts": "Daterte arbeidsfronter",
    "cases.set_up_a_new_project.step.schedule.out.programme": "Overordnet fremdriftsplan",
    "cases.set_up_a_new_project.step.schedule.title": "Legg den første fremdriftsplanen",
    "cases.set_up_a_new_project.step.schedule.what": "Åpne fremdriftsplanen og skisser hovedfasene med grove varigheter og rekkefølgen fagene følger, fra klargjøringsarbeid til overlevering. Sett startdato og måldato for ferdigstillelse.",
    "cases.set_up_a_new_project.step.schedule.why": "Selv en grov fremdriftsplan gjør et priset omfang om til daterte arbeidsfronter og viser med en gang om sluttdatoen er oppnåelig. Den gir teamet et felles bilde av jobben lenge før detaljene er på plass.",
    "cases.set_up_a_new_project.title": "Sett opp et nytt prosjekt",
    "cases.set_up_bim_requirements_and_coordination.desc": "Skriv ned hvilken informasjon byggherren faktisk trenger fra modellene, sett federerings- og koordineringsrytmen som skal levere den, og kontroller deretter at modellene som kommer tilbake har de egenskapene du ba om.",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.in.matrix": "Kravmatrise",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.in.models": "Leverte modeller",
