    "cases.set_up_bim_requirements_and_coordination.step.confirm.out.gaps": "Flaggede egenskapsmangler",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.title": "Bekreft at modellene oppfyller kravene",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.what": "Åpne de leverte modellene i visningsprogrammet og kontroller at elementene faktisk har egenskapene, klassifiseringene og detaljeringsnivået kravene ba om.",
    "cases.set_up_bim_requirements_and_coordination.step.confirm.why": "Kravet betyr bare noe hvis du kontrollerer mot det. Å fange en modell som mangler egenskaper ved levering er en ny utsendelse; å fange det ved overlevering er en kamp for å gjenoppbygge data ingen tok vare på.",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.in.matrix": "Kravmatrise",
    "cases.set_up_bim_requirements_and_coordination.step.coordinate.in.models": "Fagmodeller",
