    "cases.subcontractor_package.step.contract.out.retention": "Tilbakeholdsvilkår",
    "cases.subcontractor_package.step.contract.out.sov": "Betalingsplan",
    "cases.subcontractor_package.step.contract.title": "Sett den på kontrakt",
    "cases.subcontractor_package.step.contract.what": "Utarbeid underentreprisen med den avtalte fastprisen, betalingsplanen hvert krav skal måles mot, og tilbakeholdsprosenten du holder tilbake på hver betaling.",
    "cases.subcontractor_package.step.contract.why": "En klar betalingsplan er linjalen alle fremtidige krav måles med, så det ikke blir diskusjon om hva en betaling dekker. Tilbakeholdet du holder tilbake nå er hendelsen som får feil rettet etter at underentreprenøren har flyttet videre.",
    "cases.subcontractor_package.step.subbie.in.certs": "Forsikring og kvalifikasjoner",
    "cases.subcontractor_package.step.subbie.in.scope": "Arbeidsomfang",
    "cases.subcontractor_package.step.subbie.out.checks": "Registrerte samsvarskontroller",
    "cases.subcontractor_package.step.subbie.out.subbie": "Registrert underentreprenør",
    "cases.subcontractor_package.step.subbie.title": "Sett opp underentreprenøren",
    "cases.subcontractor_package.step.subbie.what": "Sett opp underentreprenøren med arbeidsomfanget deres, og logg kontrollene du krever før de starter: gjeldende forsikring, fagkvalifikasjoner, arbeidsbeskrivelser og eventuell prekvalifiseringsscore.",
    "cases.subcontractor_package.step.subbie.why": "En pakke er bare så pålitelig som firmaet du overlot den til. Forsikringsbeviset og kvalifikasjonskontrollene fanget opp på forhånd er det som dekker deg hvis arbeidet svikter eller et krav oppstår og papirene utfordres.",
    "cases.subcontractor_package.title": "Kjør en underentreprenørpakke",
    "cases.subcontractor_prequalification_and_onboarding.desc": "Legg forsikringen, kvalifikasjonene og sikkerhetshistorikken din frem for en hovedentreprenør én gang, bli godkjent, og bli stående på listen de inviterer for fremtidige pakker.",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.in.decision": "Godkjenningsbeslutning",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.in.profile": "Fullstendig prekvalifiseringsprofil",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.out.approved": "Godkjent leverandørstatus",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.out.list": "Sett på invitasjonsliste",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.title": "Bli godkjent og bli stående på listen",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.what": "Når du er godkjent, bekreft at du er på invitasjonslisten slik at fremtidige pakker kommer til deg automatisk i stedet for at du må spørre hver gang.",
    "cases.subcontractor_prequalification_and_onboarding.step.approved.why": "Å prekvalifisere én gang og forbli synlig på listen er det som gjør en engangsgodkjenning om til en stående rørledning av invitasjoner.",
    "cases.subcontractor_prequalification_and_onboarding.step.safety.in.history": "Sikkerhetshistorikk",
