    "journey.button.step": "Steg {{n}}",
    "journey.title": "Din prosjektreise",
    "journey.subtitle": "Hver fase av et byggeprosjekt, fra første lead til overlevering, og hvor du er akkurat nå. Velg et steg for å hoppe dit.",
    "journey.you_are_here_named": "Du er her: {{phase}}",
    "journey.here": "Her",
    "journey.always_on.title": "Alltid aktivt",
    "journey.always_on.desc": "Disse hjelper på tvers av alle faser, ikke bare én.",
    "journey.arc.plan": "Planlegg og prissett",
    "journey.arc.plan_sub": "Bestem hva som skal bygges og hva det bør koste.",
    "journey.arc.procure": "Anskaff og planlegg",
